using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    [ColumnName("Score")]
    public float[] Score { get; set; } = [];
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class ModelTrainer
{
    public static void TrainAndSave(string dataPath, string modelPath, ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        logger.LogInformation("=== Model Evaluation Metrics ===");
        logger.LogInformation("MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("LogLoss:          {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);
        logger.LogInformation(
            "Per-class metrics:\n{ConfusionMatrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {ModelPath}", modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(
    PredictionEnginePool<TicketData, TicketPrediction> predictionPool) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<ClassifyResponse> Classify([FromBody] ClassifyRequest request)
    {
        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionPool.Predict(input);

        return Ok(new ClassifyResponse
        {
            Category = prediction.PredictedCategory,
            Confidence = prediction.Score.Max()
        });
    }
}

public record ClassifyRequest
{
    public string Subject { get; init; } = string.Empty;
    public string Description { get; init; } = string.Empty;
    public int Priority { get; init; }
}

public record ClassifyResponse
{
    public string Category { get; init; } = string.Empty;
    public float Confidence { get; init; }
}

